import numpy as np
from scipy.linalg import expm
from typing import Dict, List, Tuple

class SamplingBenchmark:
    def __init__(self, n_qubits: int, beta: float = 1.0):
        self.n_qubits = n_qubits
        self.dim = 2 ** n_qubits
        self.beta = beta

        self.I = np.eye(2, dtype=complex)
        self.X = np.array([[0, 1], [1, 0]], dtype=complex)
        self.Z = np.array([[1, 0], [0, -1]], dtype=complex)

    def _single_op(self, op, qubit):
        result = np.array([[1]], dtype=complex)
        for i in range(self.n_qubits):
            result = np.kron(result, op if i == qubit else self.I)
        return result

    def generate_random_ising(self, coupling_std: float = 1.0) -> np.ndarray:
        H = np.zeros((self.dim, self.dim), dtype=complex)

        for i in range(self.n_qubits):
            for j in range(i + 1, self.n_qubits):
                J = np.random.randn() * coupling_std
                Zi = self._single_op(self.Z, i)
                Zj = self._single_op(self.Z, j)
                H -= J * Zi @ Zj

        for i in range(self.n_qubits):
            h = np.random.randn() * coupling_std * 0.5
            H -= h * self._single_op(self.Z, i)

        return H

    def exact_distribution(self, H: np.ndarray) -> np.ndarray:
        energies = np.real(np.diag(H))
        probs = np.exp(-self.beta * energies)
        return probs / np.sum(probs)

    def classical_gibbs_sample(self, H: np.ndarray, n_samples: int, burnin: int = 500) -> np.ndarray:
        energies = np.real(np.diag(H))
        current_idx = np.random.randint(self.dim)
        samples = []

        for step in range(burnin + n_samples):
            bit = np.random.randint(self.n_qubits)
            proposed_idx = current_idx ^ (1 << bit)

            dE = energies[proposed_idx] - energies[current_idx]
            if dE < 0 or np.random.random() < np.exp(-self.beta * dE):
                current_idx = proposed_idx

            if step >= burnin:
                samples.append(current_idx)

        return np.array(samples)

    def quantum_direct_sample(self, H: np.ndarray, n_samples: int, gamma: float = 0.5) -> np.ndarray:
        H_quantum = H.copy()
        for i in range(self.n_qubits):
            H_quantum -= gamma * self._single_op(self.X, i)

        exp_H = expm(-self.beta * H_quantum)
        rho = exp_H / np.trace(exp_H)

        probs = np.real(np.diag(rho))
        probs = np.clip(probs, 0, None)
        probs = probs / np.sum(probs)

        return np.random.choice(self.dim, size=n_samples, p=probs)

    def compute_tv_distance(self, samples: np.ndarray, true_dist: np.ndarray) -> float:
        counts = np.bincount(samples, minlength=self.dim)
        empirical = counts / len(samples)
        return 0.5 * np.sum(np.abs(empirical - true_dist))

    def run_benchmark(self, n_instances: int = 5, n_samples: int = 1000) -> Dict[str, List[float]]:
        results = {'classical': [], 'quantum': []}

        for _ in range(n_instances):
            H = self.generate_random_ising()
            true_dist = self.exact_distribution(H)

            classical_samples = self.classical_gibbs_sample(H, n_samples)
            results['classical'].append(self.compute_tv_distance(classical_samples, true_dist))

            quantum_samples = self.quantum_direct_sample(H, n_samples)
            results['quantum'].append(self.compute_tv_distance(quantum_samples, true_dist))

        return results
